import pytest
from typing import List, Tuple

def run_length_encode(s: str) -> List[Tuple[str, int]]:
    """
    Performs run-length encoding on a string.

    Args:
        s: The input string.

    Returns:
        A list of tuples, where each tuple contains a character and the number of times it appears consecutively.
    """
    if not s:
        return []
    result = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            count += 1
        else:
            result.append((s[i-1], count))
            count = 1
    result.append((s[-1], count))
    return result


class TestRunLengthEncode:

    def test_empty_string(self):
        assert run_length_encode("") == []

    def test_single_character(self):
        assert run_length_encode("a") == [("a", 1)]

    def test_simple_encoding(self):
        assert run_length_encode("aaabbc") == [("a", 3), ("b", 2), ("c", 1)]

    def test_mixed_case(self):
        assert run_length_encode("AaA") == [("A", 1), ("a", 1), ("A", 1)]

    def test_numbers(self):
        assert run_length_encode("11223") == [("1", 2), ("2", 2), ("3", 1)]

    def test_special_characters(self):
        assert run_length_encode("!!@@#") == [("!", 2), ("@", 2), ("#", 1)]

    def test_long_run(self):
        assert run_length_encode("aaaaaaaaaa") == [("a", 10)]

    def test_alternating_characters(self):
        assert run_length_encode("ababab") == [("a", 1), ("b", 1), ("a", 1), ("b", 1), ("a", 1), ("b", 1)]

    def test_mixed_runs(self):
        assert run_length_encode("aabbbaaccc") == [("a", 2), ("b", 3), ("a", 2), ("c", 3)]

    def test_string_with_spaces(self):
        assert run_length_encode("  a  b  ") == [(" ", 2), ("a", 1), (" ", 2), ("b", 1), (" ", 2)]

    def test_unicode_characters(self):
        assert run_length_encode("你好你好") == [("你", 1), ("好", 1), ("你", 1), ("好", 1)]

    def test_single_run(self):
        assert run_length_encode("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb") == [("b", 200)]
